<script setup lang="ts">
/**
 * Team Favicon Settings Component
 *
 * Manages the team's custom favicon. Shows current favicon preview
 * (auto-generated or custom) with upload/remove controls.
 */
const { teamId } = useTeamContext()
const { currentTeam, isAdmin } = useTeam()
const { theme } = useTeamTheme()
const { faviconHref } = useTeamFavicon()
const { t } = useT()
const notify = useNotify()

const siteSettings = useState<{ favicon?: string } | null>('team-site-settings', () => null)
const isUploading = ref(false)
const isRemoving = ref(false)

const hasCustomFavicon = computed(() => !!siteSettings.value?.favicon)

async function handleFileSelected(file: File | null) {
  if (!file || !teamId.value) return

  isUploading.value = true
  try {
    const formData = new FormData()
    formData.append('file', file)
    const result = await $fetch<{ url: string }>('/api/upload-image', {
      method: 'POST',
      body: formData
    })

    if (result?.url) {
      // Save favicon path to site settings
      const updated = await $fetch<{ favicon?: string }>(`/api/teams/${teamId.value}/settings/site`, {
        method: 'PATCH',
        body: { favicon: result.url }
      })
      siteSettings.value = { ...siteSettings.value, ...updated }
      notify.success(t('teams.favicon.uploaded') || 'Favicon uploaded')
    }
  }
  catch (e: unknown) {
    const message = e instanceof Error ? e.message : 'Failed to upload favicon'
    notify.error(t('common.error') || 'Error', { description: message })
  }
  finally {
    isUploading.value = false
  }
}

async function removeFavicon() {
  if (!teamId.value) return

  isRemoving.value = true
  try {
    const updated = await $fetch<{ favicon?: string }>(`/api/teams/${teamId.value}/settings/site`, {
      method: 'PATCH',
      body: { favicon: '' }
    })
    siteSettings.value = { ...siteSettings.value, favicon: undefined }
    notify.success(t('teams.favicon.removed') || 'Custom favicon removed')
  }
  catch (e: unknown) {
    const message = e instanceof Error ? e.message : 'Failed to remove favicon'
    notify.error(t('common.error') || 'Error', { description: message })
  }
  finally {
    isRemoving.value = false
  }
}
</script>

<template>
  <div class="space-y-4">
    <div>
      <h3 class="text-lg font-semibold">
        {{ t('teams.favicon.title') || 'Favicon' }}
      </h3>
      <p class="text-sm text-muted mt-1">
        {{ t('teams.favicon.description') || 'Customize the browser tab icon for your team. By default, an icon is generated from your team name and theme color.' }}
      </p>
    </div>

    <div class="flex items-center gap-6">
      <!-- Favicon Preview -->
      <div class="flex flex-col items-center gap-2">
        <div class="flex items-center justify-center size-16 rounded-lg border border-default bg-muted/30">
          <img
            :src="faviconHref"
            alt="Current favicon"
            class="size-8"
          >
        </div>
        <span class="text-xs text-muted">
          {{ hasCustomFavicon ? (t('teams.favicon.custom') || 'Custom') : (t('teams.favicon.autoGenerated') || 'Auto-generated') }}
        </span>
      </div>

      <!-- Upload / Remove Actions -->
      <div class="flex flex-col gap-2">
        <CroutonImageUpload
          :crop="{ aspectRatio: 1 }"
          class="w-48"
          :disabled="!isAdmin || isUploading"
          @file-selected="handleFileSelected"
        />
        <UButton
          v-if="hasCustomFavicon"
          variant="ghost"
          color="error"
          size="xs"
          icon="i-lucide-trash-2"
          :loading="isRemoving"
          :disabled="!isAdmin"
          @click="removeFavicon"
        >
          {{ t('teams.favicon.removeCustom') || 'Remove custom favicon' }}
        </UButton>
      </div>
    </div>
  </div>
</template>
